/**
 * Hook for saved materials (mindmaps, quizzes, flashcards)
 *
 * Replaces localStorage usage with database API.
 * Issue #64: Consolidate localStorage to Database
 */

import { useState, useEffect, useCallback } from 'react';
import { logger } from '@/lib/logger';
import type { ToolType } from '@/types/tools';
import type { Subject } from '@/types';

// Material types matching the API
export interface SavedMaterial {
  id: string;
  toolId: string;
  toolType: ToolType;
  title: string;
  content: Record<string, unknown>;
  maestroId?: string;
  sessionId?: string;
  subject?: string;
  preview?: string;
  status: 'active' | 'archived' | 'deleted';
  userRating?: number;
  isBookmarked: boolean;
  viewCount: number;
  createdAt: string;
  updatedAt: string;
}

// Mindmap-specific type
export interface SavedMindmap {
  id: string;
  title: string;
  nodes: MindmapNode[];
  subject: Subject;
  createdAt: Date;
  maestroId?: string;
}

interface MindmapNode {
  id: string;
  label: string;
  children?: MindmapNode[];
  icon?: string;
  color?: string;
}

// Quiz-specific type
export interface SavedQuiz {
  id: string;
  title: string;
  subject: string;
  questions: QuizQuestion[];
  createdAt: Date;
}

interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
  explanation?: string;
}

// Flashcard deck type
export interface SavedFlashcardDeck {
  id: string;
  name: string;
  subject: string;
  cards: FlashcardCard[];
  createdAt: Date;
}

interface FlashcardCard {
  front: string;
  back: string;
}

// Homework-specific types
export interface HomeworkStep {
  id: string;
  description: string;
  hints: string[];
  studentNotes: string;
  completed: boolean;
}

export interface SavedHomework {
  id: string;
  title: string;
  subject: Subject;
  problemType: string;
  photoUrl?: string;
  steps: HomeworkStep[];
  createdAt: Date;
  completedAt?: Date;
}

// Get default user ID - will be replaced by proper auth
function getUserId(): string {
  // In production, this would come from auth context
  // For now, use a session-based ID
  if (typeof window === 'undefined') return 'default-user';

  let userId = sessionStorage.getItem('convergio-user-id');
  if (!userId) {
    userId = `user-${crypto.randomUUID()}`;
    sessionStorage.setItem('convergio-user-id', userId);
  }
  return userId;
}

/**
 * Fetch materials from API
 */
async function fetchMaterials(
  toolType: ToolType,
  userId: string
): Promise<SavedMaterial[]> {
  try {
    const response = await fetch(
      `/api/materials?userId=${userId}&toolType=${toolType}&status=active`
    );
    if (!response.ok) {
      throw new Error(`API error: ${response.status}`);
    }
    const data = await response.json();
    return data.materials || [];
  } catch (error) {
    logger.error('Failed to fetch materials', { error, toolType });
    return [];
  }
}

/**
 * Save material to API
 */
async function saveMaterialToAPI(
  userId: string,
  toolType: ToolType,
  title: string,
  content: Record<string, unknown>,
  options?: {
    subject?: string;
    maestroId?: string;
    preview?: string;
  }
): Promise<SavedMaterial | null> {
  try {
    const toolId = crypto.randomUUID();
    const response = await fetch('/api/materials', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId,
        toolId,
        toolType,
        title,
        content,
        ...options,
      }),
    });
    if (!response.ok) {
      throw new Error(`API error: ${response.status}`);
    }
    const data = await response.json();
    return data.material;
  } catch (error) {
    logger.error('Failed to save material', { error, toolType, title });
    return null;
  }
}

/**
 * Delete material via API
 */
async function deleteMaterialFromAPI(toolId: string): Promise<boolean> {
  try {
    const response = await fetch(`/api/materials?toolId=${toolId}`, {
      method: 'DELETE',
    });
    return response.ok;
  } catch (error) {
    logger.error('Failed to delete material', { error, toolId });
    return false;
  }
}

/**
 * Update material via API
 */
async function updateMaterialInAPI(
  toolId: string,
  content: Record<string, unknown>,
  title?: string
): Promise<boolean> {
  try {
    const response = await fetch('/api/materials', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ toolId, content, title }),
    });
    return response.ok;
  } catch (error) {
    logger.error('Failed to update material', { error, toolId });
    return false;
  }
}

